<template>
    <BaseModal
        name="player-plugins"
       :full="true"
    >
        <template v-slot:content>
            <div class="player-plugins-box"
            >
                <Menu
                    :items="categories"
                    :code="data.category"
                    @change="setCategory"
                />
                

                <Field
                    icon="search"
                    placeholder="..."
                    class="noerror light"
                    @change="onSearchChange"
                />


                <div class="loader" v-if="data.loading">
                    <div>
                        <Loader :inside="true" class="tertiary" />
                    </div>
                </div>

                <div class="plugins-list" v-else>
                    <div class="plugin"
                        v-if="plugins.length"
                        :class="{ 'is-active': !playerPlugin.plugin?.code }"
                        @click="clearPlugin"
                    >
                        <Img
                            :preview="'https://plugins.bilbomusic.com/img/plugin/crop/bilbo.jpg'"
                            :original="'https://plugins.bilbomusic.com/img/plugin/original/bilbo.jpg'"
                            aspectRatio="419 / 140"
                            :skeleton="true"
                        />
                    </div>

                    <div class="plugin"
                        v-for="item in plugins"
                        :key="item.code"
                        :class="{ 'is-active': playerPlugin.plugin?.code === item.code }"
                        @click="setPlugin(item)"
                    >
                        <Img
                            :preview="item.cover.crop"
                            :original="item.cover.original"
                            :alt="item.name"
                            aspectRatio="419 / 140"
                            :skeleton="true"
                        />
                    </div>


                    <EmptyLabel
                        v-if="!plugins.length && !data.loading"
                        class="empty"
                        title="Плагины не найдены"
                        description="Попробуйте изменить запрос"
                    />
                </div>
            </div>
        </template>
    </BaseModal>
</template>

<script setup>
import { reactive, onMounted, computed, ref, watch } from 'vue';
import { useI18n } from 'vue-i18n';

import BaseModal from '🔗/components/modals/BaseModal.vue';
import Loader from '🔗/components/ui/Loader.vue';
import IconButton from '🔗/components/ui/IconButton.vue';
import Button from '🔗/components/ui/Button.vue';
import Field from '🔗/components/ui/Field.vue';
import EmptyLabel from '🔗/components/ui/EmptyLabel.vue';
import Img from '🔗/components/ui/Img.vue';
import Menu from '🔗/components/ui/Menu.vue';

// import api from '🔗/api';
import stores from '@/stores';

// const others = stores.others();
const player = stores.player();
const playerPlugin = stores.playerPlugin();
const modals = stores.modals();


const { t } = useI18n();


    const categories = ref([
        {
            code: '',
            name: 'All'
        }, {
            code: 'visualizer',
            name: 'Visualizers'
        }, {
            code: 'game',
            name: 'Games & Co'
        }
    ]);

    const data = reactive({
        loading: true,
        category: '',
        plugins: [],
        searchStr: ''
    });

    const plugins = computed(() => {
        let list = data.plugins;

        if (data.searchStr?.length) {
            const searchStr = data.searchStr.toLowerCase().trim();

            list = list.filter(item => {
                return item.name?.includes(searchStr) || item.description?.includes(searchStr);
            })
        }

        if (!data.category) {
            return list;
        }

        return list.filter(item => item.category === data.category);
    });

    const setCategory = (category) => {
        data.category = category;
    }

    const onSearchChange = async (e) => {
        data.searchStr = e.target.value?.toLowerCase().trim() || '';

        // clearTimeout(data.searchTimeout);

        // data.searchTimeout = setTimeout(() => {
        //     delete data.searchTimeout;
        //     getItems();
        // }, 200);
    }

    const getItems = async () => {
        data.loading = true;

        // Логика поиска, фильтра, пагинации будет реализована потом, когда будет бэк ToDo

        try {
            const response = await fetch('https://plugins.bilbomusic.com/plugins.json')
            if (response.ok) {
                const items = await response.json()
                if (Array.isArray(items) && items.length > 0) {
                    data.plugins = items;
                }
            }
        } catch (error) {
        }

        data.loading = false;
    }

    onMounted(async () => {
        await getItems();
    });


    const setPlugin = (item) => {
        if (item.code === playerPlugin.plugin?.code) {
            close();
            return;
        }

        modals.open('loader', {data: { light: true }});
        playerPlugin.setPlugin(item);
    }

    const clearPlugin = () => {
        playerPlugin.clearPlugin();
        close();
    }

    const close = () => {
        modals.close('player-plugins');
    }

    watch(
        () => playerPlugin.isIframeReady,
        (value) => {
            if (value) {
                setTimeout(() => {
                    modals.close('loader')
                    player.expand();

                    close();
                }, 100);
            }
        }
    );
</script>

<style lang="scss" scoped>
    .player-plugins-box {
        display: flex;
        flex-direction: column;
        gap: 16px;
        flex: 1;
        padding-top: calc(var(--max-safe-area-inset-top, var(--tg-safe-area-inset-top, 0px)) + var(--max-content-safe-area-inset-top, var(--tg-content-safe-area-inset-top, 0px)) + 12px);

        
        .loader {
            @include inside-loader;
        }


        .plugins-list {
            display: flex;
            flex-direction: column;
            gap: 4px;

            .plugin {
                width: 100%;
                background-size: cover;
                background-position: center;
                display: flex;
                align-items: center;
                justify-content: flex-end;
                border-radius: 8px;
                position: relative;
                cursor: pointer;
                box-sizing: border-box;
                border: 2px solid transparent;
                transition: all 0.25s cubic-bezier(0.16, 1, 0.3, 1);
                box-shadow: inset 0 0 50px rgba(0,0,0,0.65), 0 4px 12px rgba(0,0,0,0.25);
                overflow: hidden;

                img {
                    border-radius: 8px;
                }

                &::before {
                    content: '';
                    position: absolute;
                    top: 0; left: 0; right: 0; bottom: 0;
                    background: rgba(0,0,0,0.2);
                    border-radius: 6px;
                    transition: opacity 0.2s ease;
                }

                // &:hover::before {
                //     background: rgba(0,0,0,0.05);
                // }

                // &:hover {
                //     border-color: #34343d;
                //     transform: translateY(-1px);
                //     box-shadow: inset 0 0 50px rgba(0,0,0,0.5), 0 6px 16px rgba(0,0,0,0.35);
                // }

                &.is-active {
                    &:before {
                        background: rgba(0,0,0,0.05);
                    }

                    border-color: var(--color--option-5);
                    box-shadow: 0 0 4px var(--color--option-5), inset 0 0 45px rgba(0,0,0,0.35);
                }
            }
        }
    }
</style>
